Url = useBaseUrl(imageUrl); // Use the useBaseUrl function to generate the image URL\n\n  return (\n    <span>\n      {/* Button to toggle visibility of the image */}\n      <a onClick={() => setShowImg(!showImg)} className={styles.cursor}>\n        {buttonName}  \n      </a>\n      {/* Conditionally render the image if showImg is true */}\n      {showImg && (\n        <div className={styles.imageonclick} onClick={() => setShowImg(false)}>\n          {/* Close button */}\n          <button \n            className={styles.closeButton}\n            onClick={(e) => {\n              e.stopPropagation();\n              setShowImg(false);\n            }}\n            aria-label=\"Close image\"\n          >\n            \u2715\n          </button>\n          {/* Image element */}\n          <img \n            src={generatedImageUrl} \n            alt={altText} \n            onClick={(e) => e.stopPropagation()}\n          /> \n        </div>\n      )}\n    </span>\n  );\n}\n\nexport default ImageOnClick; // Export the ImageOnClick component\n"})}),"\n",(0,o.jsx)(n.h2,{id:"css",children:"CSS"}),"\n",(0,o.jsx)(n.p,{children:"To center the image and apply modern lightbox effects, we'll add some CSS:"}),"\n",(0,o.jsx)(n.pre,{children:(0,o.jsx)(n.code,{className:"language-css",metastring:'title="src\\components\\ImageOnClick\\styles.module.css"',children:"/* Modern lightbox overlay */\n.imageonclick {\n  position: fixed;\n  top: 0;\n  left: 0;\n  width: 100vw;\n  height: 100vh;\n  background: radial-gradient(circle, rgba(0, 0, 0, 0.4) 0%, rgba(0, 0, 0, 0.9) 100%);\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  z-index: 9999;\n  backdrop-filter: blur(8px);\n  animation: lightboxFadeIn 0.4s cubic-bezier(0.25, 0.46, 0.45, 0.94);\n  cursor: pointer;\n}\n\n/* Image with elegant zoom effect */\n.imageonclick img {\n  max-width: 90%;\n  max-height: 90%;\n  width: auto;\n  height: auto;\n  object-fit: contain;\n  border-radius: 16px;\n  box-shadow: \n    0 25px 80px rgba(0, 0, 0, 0.8),\n    0 0 0 1px rgba(255, 255, 255, 0.1);\n  animation: imageZoomIn 0.5s cubic-bezier(0.34, 1.56, 0.64, 1);\n  cursor: default;\n  transition: transform 0.3s ease;\n}\n\n.imageonclick img:hover {\n  transform: scale(1.02);\n}\n\n/* Modern close button */\n.closeButton {\n  position: absolute;\n  top: 20px;\n  right: 20px;\n  color: white;\n  font-size: 24px;\n  font-weight: 400;\n  cursor: pointer;\n  z-index: 10001;\n  width: 48px;\n  height: 48px;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  border-radius: 24px;\n  background: linear-gradient(135deg, rgba(255, 255, 255, 0.1), rgba(255, 255, 255, 0.05));\n  border: 1px solid rgba(255, 255, 255, 0.2);\n  backdrop-filter: blur(10px);\n  transition: all 0.3s cubic-bezier(0.25, 0.46, 0.45, 0.94);\n  animation: buttonSlideIn 0.6s cubic-bezier(0.34, 1.56, 0.64, 1) 0.2s both;\n}\n\n.closeButton:hover {\n  background: linear-gradient(135deg, rgba(255, 255, 255, 0.2), rgba(255, 255, 255, 0.1));\n  transform: scale(1.1) rotate(90deg);\n  border-color: rgba(255, 255, 255, 0.4);\n}\n\n.closeButton:active {\n  transform: scale(0.95) rotate(90deg);\n}\n\n/* Enhanced animations */\n@keyframes lightboxFadeIn {\n  from {\n    opacity: 0;\n    backdrop-filter: blur(0px);\n    background: radial-gradient(circle, rgba(0, 0, 0, 0) 0%, rgba(0, 0, 0, 0) 100%);\n  }\n  to {\n    opacity: 1;\n    backdrop-filter: blur(8px);\n    background: radial-gradient(circle, rgba(0, 0, 0, 0.4) 0%, rgba(0, 0, 0, 0.9) 100%);\n  }\n}\n\n@keyframes imageZoomIn {\n  from {\n    transform: scale(0.5) translateY(60px);\n    opacity: 0;\n    filter: blur(4px);\n  }\n  50% {\n    opacity: 0.8;\n    filter: blur(2px);\n  }\n  to {\n    transform: scale(1) translateY(0);\n    opacity: 1;\n    filter: blur(0px);\n  }\n}\n\n@keyframes buttonSlideIn {\n  from {\n    transform: translateY(-20px) scale(0.8);\n    opacity: 0;\n  }\n  to {\n    transform: translateY(0) scale(1);\n    opacity: 1;\n  }\n}\n\n/* Enhanced responsive design */\n@media (max-width: 768px) {\n  .closeButton {\n    top: 15px;\n    right: 15px;\n    width: 44px;\n    height: 44px;\n    font-size: 20px;\n  }\n\n  .imageonclick img {\n    max-width: 95%;\n    max-height: 85%;\n    border-radius: 12px;\n  }\n}\n\n@media (max-width: 480px) {\n  .closeButton {\n    top: 10px;\n    right: 10px;\n    width: 40px;\n    height: 40px;\n    font-size: 18px;\n  }\n\n  .imageonclick img {\n    max-width: 98%;\n    max-height: 80%;\n    border-radius: 8px;\n  }\n}\n\n/* Exit animation (optional) */\n.imageonclick.closing {\n  animation: lightboxFadeOut 0.3s ease-out forwards;\n}\n\n.imageonclick.closing img {\n  animation: imageZoomOut 0.3s ease-out forwards;\n}\n\n@keyframes lightboxFadeOut {\n  to {\n    opacity: 0;\n    backdrop-filter: blur(0px);\n  }\n}\n\n@keyframes imageZoomOut {\n  to {\n    transform: scale(0.8) translateY(20px);\n    opacity: 0;\n  }\n}\n"})}),"\n",(0,o.jsx)(n.h2,{id:"using",children:"Using the Component in an MDX File"}),"\n",(0,o.jsx)(n.h3,{id:"basic",children:"Basic"}),"\n",(0,o.jsx)(n.pre,{children:(0,o.jsx)(n.code,{className:"language-html",children:'<ImageOnClick imageUrl="/img/friends.jpg" altText="Dinosaur" buttonName="Click me" />\n'})}),"\n",(0,o.jsx)(i,{imageUrl:"/img/friends.jpg",altText:"Dinosaur",buttonName:"Click me"}),"\n",(0,o.jsx)(n.h3,{id:"emoji-button",children:"Emoji Button"}),"\n",(0,o.jsx)(n.pre,{children:(0,o.jsx)(n.code,{className:"language-html",children:'<ImageOnClick imageUrl="/img/friends.jpg" altText="Dinosaur" buttonName="\u{1F50E}" />\n'})}),"\n",(0,o.jsxs)(n.p,{children:["Using markdown emoji: ",(0,o.jsx)(i,{imageUrl:"/img/friends.jpg",altText:"Dinosaur",buttonName:"\u{1F50E}"})]}),"\n",(0,o.jsx)(s,{model:"teacher",text:"Markdown",position:"top",children:(0,o.jsx)(n.p,{children:"Markdown is a lightweight markup language\nwith plain-text-formatting\nsyntax that can be converted\nto HTML and many other formats."})})]})}function m(e={}){let{wrapper:n}={...(0,a.